('G4462','G','ῥαββονί','rhabboní','hrab-bon-ee''','','corresponding to',':--Lord, Rabboni.'),
('G4463','G','ῥαβδίζω','rhabdízō','hrab-did''-zo','','to strike with a stick, i.e. bastinado',':--beat (with rods).'),
('G4464','G','ῥάβδος','rhábdos','hrab''-dos','','a stick or wand (as a cudgel, a cane or a baton  of royalty)',':--rod, sceptre, staff.'),
('G4465','G','ῥαβδοῦχος','rhabdoûchos','hrab-doo''-khos','','a rod- (the Latin fasces) holder, i.e. a Roman  lictor (constable or executioner)',':--serjeant.'),
('G4466','G','Ῥαγαῦ','Rhagaû','hrag-ow''','','Ragau (i.e. Reu), a patriarch',':--Ragau.'),
('G4467','G','ῥᾳδιούργημα','rhaidioúrgēma','hrad-ee-oorg''-ay-mah','','easy-going behavior, i.e. (by extension) a crime',':--lewdness.'),
('G4468','G','ῥᾳδιουργία','rhaidiourgía','hrad-ee-oorg-ee''-a','','recklessness, i.e. (by extension)  malignity',':--mischief.'),
