('G4479','G','Ῥεβέκκα','Rhebékka','hreb-bek''-kah','','Rebecca (i.e. Ribkah), the wife of  Isaac',':--Rebecca.'),
('G4480','G','ῥέδα','rhéda','hred''-ah','','a rheda, i.e. four-wheeled carriage (wagon for  riding)',':--chariot.'),
('G4481','G','Ῥεμφάν','Rhemphán','hrem-fan''','','Remphan (i.e. Kijun), an Egyptian idol',':--Remphan.'),
('G4482','G','ῥέω','rhéō','hreh''-o','','for some tenses of which a prolonged form          is used   to flow ("run"; as water)',':--flow.'),
('G4483','G','ῥέω','rhéō','hreh''-o','','to utter, i.e. speak or say',':--command, make, say, speak (of).  Compare'),
('G4484','G','Ῥήγιον','Rhḗgion','hrayg''-ee-on','','Rhegium, a place in Italy',':--Rhegium.'),
('G4485','G','ῥῆγμα','rhēgma','hrayg''-mah','','something torn, i.e. a fragment (by implication and  abstractly, a fall)',':--ruin.'),
('G4486','G','ῥήγνυμι','rhḗgnymi','hrayg''-noo-mee','','being its intensive (with the  preposition in composition), and  a shattering to minute  fragments; but not a reduction to the constituent particles, like  ) or disrupt, lacerate; by implication, to convulse (with spasms);  figuratively, to give vent to joyful emotions',':--break (forth), burst,  rend, tear.'),
('G4487','G','ῥῆμα','rhēma','hray''-mah','','an utterance (individually, collectively or specially),; by  implication, a matter or topic (especially of narration, command or  dispute); with a negative naught whatever',':--+ evil, + nothing, saying,  word.'),
('G4488','G','Ῥησά','Rhēsá','hray-sah''','','Resa (i.e. Rephajah),  an Israelite',':--Rhesa.'),
('G4489','G','ῥήτωρ','rhḗtōr','hray''-tore','','a speaker, i.e. (by implication) a forensic  advocate',':--orator.'),
('G4490','G','ῥητῶς','rhētōs','hray-toce''','','out-spokenly, i.e.  distinctly',':--expressly.'),
('G4491','G','ῥίζα','rhíza','hrid''-zah','','a "root" (literally or  figuratively)',':--root.'),
('G4492','G','ῥιζόω','rhizóō','hrid-zo''-o','','to root (figuratively, become stable)',':--root.'),
('G4493','G','ῥιπή','rhipḗ','hree-pay''','','a jerk (of the eye, i.e. (by analogy) an  instant)',':--twinkling.'),
('G4494','G','ῥιπίζω','rhipízō','hrip-id''-zo','','to breeze up,  i.e. (by analogy) to agitate (into waves)',':--toss.'),
('G4495','G','ῥιπτέω','rhiptéō','hrip-teh''-o','','to toss up',':--cast off.'),
('G4496','G','ῥίπτω','rhíptō','hrip''-to','','to fling (properly, with a quick toss, thus  differing from , which denotes a deliberate hurl; and from   (see in ), which indicates an extended projection); by  qualification, to deposit (as if a load); by extension, to  disperse',':--cast (down, out), scatter abroad, throw.'),
('G4497','G','Ῥοβοάμ','Rhoboám','hrob-o-am''','','Roboam (i.e. Rechobam), an  Israelite',':--Roboam.'),
('G4498','G','Ῥόδη','Rhódē','hrod''-ay','','Rode, a servant girl',':--Rhoda.'),
('G4499','G','Ῥόδος','Rhódos','hrod''-os','','Rhodus, an island of the  Mediterranean',':--Rhodes.'),
('G4500','G','ῥοιζηδόν','rhoizēdón','hroyd-zay-don''','','whizzingly, i.e. with a  crash',':--with a great noise.')
