('G5381','G','φιλονεξία','philonexía','fil-on-ex-ee''-ah','','hospitableness',':--entertain stranger, hospitality.'),
('G5382','G','φιλόξενος','philóxenos','fil-ox''-en-os','','fond of guests, i.e. hospitable',':--given to (lover  of, use) hospitality.'),
('G5383','G','φιλοπρωτεύω','philoprōteúō','fil-op-rote-yoo''-o','','to be fond of being first, i.e.  ambitious of distinction',':--love to have the preeminence.'),
('G5384','G','φίλος','phílos','fee''-los','','actively, fond, i.e. friendly (still as  a noun, an associate, neighbor, etc.)',':--friend.'),
('G5385','G','φιλοσοφία','philosophía','fil-os-of-ee''-ah','','"philosophy", i.e. (specially), Jewish  sophistry',':--philosophy.'),
('G5386','G','φιλόσοφος','philósophos','fil-os''-of-os','','fond of wise things, i.e. a  "philosopher"',':--philosopher.'),
('G5387','G','φιλόστοργος','philóstorgos','fil-os''-tor-gos','','fond of natural relatives, i.e. fraternal towards fellow  Christian',':--kindly affectioned.'),
('G5388','G','φιλότεκνος','philóteknos','fil-ot''-ek-nos','','fond of one''s children, i.e. maternal',':--love their  children.'),
('G5389','G','φιλοτιμέομαι','philotiméomai','fil-ot-im-eh''-om-ahee','','to be fond of honor,  i.e. emulous (eager or earnest to do something)',':--labour, strive,  study.'),
('G5390','G','φιλοφρόνως','philophrónōs','fil-of-ron''-oce','','with friendliness of mind, i.e.  kindly',':--courteously.'),
('G5391','G','φιλόφρων','philóphrōn','fil-of''-rone','','friendly of mind, i.e. kind',':--courteous.'),
('G5392','G','φιμόω','phimóō','fee-mo''-o','','to muzzle',':--muzzle.'),
('G5393','G','Φλέγων','Phlégōn','fleg''-one','','blazing; Phlegon, a  Christian',':--Phlegon.'),
('G5394','G','φλογίζω','phlogízō','flog-id''-zo','','to cause a blaze, i.e. ignite (figuratively, to inflame  with passion)',':--set on fire.'),
('G5395','G','φλόξ','phlóx','flox','','a blaze',':--flame(-ing).'),
('G5396','G','φλυαρέω','phlyaréō','floo-ar-eh''-o','','to be a babbler or trifler, i.e. (by implication) to berate  idly or mischievously',':--prate against.'),
('G5397','G','φλύαρος','phlýaros','floo''-ar-os','','a garrulous person, i.e. prater',':--tattler.'),
('G5398','G','φοβερός','phoberós','fob-er-os''','','frightful, i.e. (objectively) formidable',':--fearful,  terrible.'),
('G5399','G','φοβέω','phobéō','fob-eh''-o','','to frighten, i.e. (passively) to be alarmed; by analogy, to  be in awe of, i.e. revere',':--be (+ sore) afraid, fear (exceedingly),  reverence.'),
('G5400','G','φόβητρον','phóbētron','fob''-ay-tron','','a frightening thing, i.e. terrific  portent',':--fearful sight.'),
('G5401','G','φόβος','phóbos','fob''-os','','alarm or fright',':--be  afraid, + exceedingly, fear, terror.'),
('G5402','G','Φοίβη','Phoíbē','foy''-bay','','probably akin to the base of );  Phœbe, a Christian woman',':--Phebe.'),
