('G5404','G','φοῖνιξ','phoînix','foy''-nix','','a palm-tree',':--palm (tree).'),
('G5405','G','Φοῖνιξ','Phoînix','foy''-nix','','Phœnix, a place in Crete',':--Phenice.'),
('G5406','G','φονεύς','phoneús','fon-yooce''','','a murderer (always of criminal (or at least intentional)  homicide; which  does not necessarily imply; while  is a  special term for a public bandit)',':--murderer.'),
('G5407','G','φονεύω','phoneúō','fon-yoo''-o','','to be a murderer (of)',':--kill, do murder, slay.'),
('G5408','G','φόνος','phónos','fon''-os','','murder',':--murder, + be slain  with, slaughter.'),
('G5409','G','φορέω','phoréō','for-eh''-o','','to have a burden, i.e. (by analogy) to wear as clothing or  a constant accompaniment',':--bear, wear.'),
('G5410','G','Φόρον','Phóron','for''-on','','a forum or market-place; only in comparative with  ; a station on the Appian road',':--forum.'),
('G5411','G','φόρος','phóros','for''-os','','a load (as borne), i.e. (figuratively) a tax (properly, an  individual assessment on persons or property; whereas  is usually  a general toll on goods or travel)',':--tribute.'),
('G5412','G','φορτίζω','phortízō','for-tid''-zo','','to load up (properly, as a vessel or animal), i.e.  (figuratively) to overburden with ceremony (or spiritual  anxiety)',':--lade, by heavy laden.'),
('G5413','G','φορτίον','phortíon','for-tee''-on','','an invoice (as part of freight), i.e.  (figuratively) a task or service',':--burden.'),
('G5414','G','φόρτος','phórtos','for''-tos','','something carried, i.e. the cargo of a ship',':--lading.'),
('G5415','G','Φορτουνᾶτος','Phortounâtos','for-too-nat''-os','','"fortunate"; Fortunatus, a Christian',':--Fortunatus.'),
('G5416','G','φραγέλλιον','phragéllion','frag-el''-le-on','','a whip, i.e. Roman lash  as a public punishment',':--scourge.'),
('G5417','G','φραγελλόω','phragellóō','frag-el-lo''-o','','to whip, i.e. lash  as a public punishment',':--scourge.'),
('G5418','G','φραγμός','phragmós','frag-mos''','','a fence, or inclosing barrier (literally or  figuratively)',':--hedge (+ round about), partition.'),
('G5419','G','φράζω','phrázō','frad''-zo','','to indicate (by  word or act), i.e. (specially), to expound',':-- declare.'),
('G5420','G','φράσσω','phrássō','fras''-so','','to fence or  inclose, i.e. (specially), to block up (figuratively, to  silence)',':--stop.'),
('G5421','G','φρέαρ','phréar','freh''-ar','','a hole in the ground (dug for obtaining or  holding water or other purposes), i.e. a cistern or well;  figuratively, an abyss (as a prison)',':--well, pit.'),
('G5422','G','φρεναπατάω','phrenapatáō','fren-ap-at-ah''-o','','to be a mind-misleader, i.e. delude',':--deceive.'),
('G5423','G','φρεναπάτης','phrenapátēs','fren-ap-at''-ace','','a mind-misleader, i.e. seducer',':--deceiver.'),
('G5424','G','φρήν','phrḗn','frane','','the midrif (as a partition of the body), i.e. (figuratively and by  implication, of sympathy) the feelings (or sensitive nature; by  extension (also in the plural) the mind or cognitive  faculties)',':--understanding.'),
('G5425','G','φρίσσω','phríssō','fris''-so','','to "bristle" or chill, i.e. shudder  (fear)',':--tremble.'),
('G5426','G','φρονέω','phronéō','fron-eh''-o','','to exercise the mind, i.e. entertain or have a sentiment or  opinion; by implication, to be (mentally) disposed (more or less  earnestly in a certain direction); intensively, to interest oneself in  (with concern or obedience)',':--set the affection on, (be) care(-ful),  (be like-, + be of one, + be of the same, + let this) mind(-ed),  regard, savour, think.'),
('G5427','G','φρόνημα','phrónēma','fron''-ay-mah','','(mental) inclination or purpose',':--(be, + be carnally, + be  spiritually) mind(-ed).'),
('G5428','G','φρόνησις','phrónēsis','fron''-ay-sis','','mental action or activity, i.e. intellectual or moral  insight',':--prudence, wisdom.'),
('G5429','G','φρόνιμος','phrónimos','fron''-ee-mos','','thoughtful, i.e. sagacious or discreet (implying a cautious  character; while  denotes practical skill or acumen; and   indicates rather intelligence or mental acquirement); in a bad sense  conceited (also in the comparative)',':--wise(-r).'),
('G5430','G','φρονίμως','phronímōs','fron-im''-oce','','prudently',':--wisely.'),
('G5431','G','φροντίζω','phrontízō','fron-tid''-zo','','to exercise thought, i.e. be anxious',':--be  careful.'),
('G5432','G','φρουρέω','phrouréō','froo-reh''-o','','to be a watcher in advance, i.e. to  mount guard as a sentinel (post spies at gates); figuratively, to hem  in, protect',':--keep (with a garrison). Compare'),
('G5433','G','φρυάσσω','phryássō','froo-as''-so','','to snort (as a spirited horse), i.e.  (figuratively) to make a tumult',':--rage.'),
