('G5437','G','φυγή','phygḗ','foog-ay''','','a fleeing, i.e. escape',':--flight.'),
('G5438','G','φυλακή','phylakḗ','foo-lak-ay''','','a guarding or (concretely, guard), the act, the person;  figuratively, the place, the condition, or (specially), the time (as a  division of day or night), literally or figuratively',':--cage, hold,  (im-)prison(-ment), ward, watch.'),
('G5439','G','φυλακίζω','phylakízō','foo-lak-id''-zo','','to incarcerate',':--imprison.'),
('G5440','G','φυλακτήριον','phylaktḗrion','foo-lak-tay''-ree-on','','a guard-case, i.e. "phylactery" for  wearing slips of Scripture texts',':-- phylactery.'),
('G5441','G','φύλαξ','phýlax','foo''-lax','','a watcher or sentry',':--keeper.'),
('G5442','G','φυλάσσω','phylássō','foo-las''-so','','to watch, i.e. be on  guard (literally of figuratively); by implication, to preserve, obey,  avoid',':--beward, keep (self), observe, save. Compare'),
