('G5462','G','φωτισμός','phōtismós','fo-tis-mos''','','illumination (figuratively)',':--light.'),
('G5463','G','χαίρω','chaírō','khah''-ee-ro','','to be "cheer"ful, i.e. calmly happy or well-off;  impersonally, especially as salutation (on meeting or parting), be  well',':--farewell, be glad, God speed, greeting, hall, joy(- fully),  rejoice.'),
('G5464','G','χάλαζα','chálaza','khal''-ad-zah','','hail',':--hail.'),
