('G5489','G','χάρτης','chártēs','khar''-tace','','a sheet ("chart") of writing-material (as to be  scribbled over)',':--paper.'),
('G5490','G','χάσμα','chásma','khas''-mah','','a  "chasm" or vacancy (impassable interval)',':--gulf.'),
('G5491','G','χεῖλος','cheîlos','khi''-los','','a lip (as a pouring place);  figuratively, a margin (of water)',':--lip, shore.'),
('G5492','G','χειμάζω','cheimázō','khi-mad''-zo','','to storm, i.e. (passively) to labor under a  gale',':--be tossed with tempest.'),
('G5493','G','χείμαῤῥος','cheímarrhos','khi''-mar-hros','','a storm-runlet, i.e.  winter-torrent',':--brook.'),
('G5494','G','χειμών','cheimṓn','khi-mone''','','akin to the base of 5490 through  the idea of a channel), meaning a storm (as pouring rain); by  implication, the rainy season, i.e. winter',':--tempest, foul weather,  winter.'),
('G5495','G','χείρ','cheír','khire','','the hand  (literally or figuratively (power); especially (by Hebraism) a means  or instrument)',':--hand.'),
('G5496','G','χειραγωγέω','cheiragōgéō','khi-rag-ogue-eh''-o','','to be a hand-leader, i.e. to guide (a blind person)',':--lead  by the hand.'),
('G5497','G','χειραγωγός','cheiragōgós','khi-rag-o-gos''','','a hand-leader, i.e. personal  conductor (of a blind person)',':--some to lead by the hand.'),
('G5498','G','χειρόγραφον','cheirógraphon','khi-rog''-raf-on','','something hand-written  ("chirograph"), i.e. a manuscript (specially, a legal document or bond  (figuratively))',':--handwriting.'),
('G5499','G','χειροποίητος','cheiropoíētos','khi-rop-oy''-ay-tos','','manufactured, i.e. of human  construction',':--made by (make with) hands.'),
('G5500','G','χειροτονέω','cheirotonéō','khi-rot-on-eh''-o','','to be a  hand-reacher or voter (by raising the hand), i.e. (generally) to  select or appoint',':--choose, ordain.')
