('G5504','G','χθές','chthés','khthes','','"yesterday"; by extension, in time past or  hitherto',':--yesterday.'),
('G5505','G','χιλιάς','chiliás','khil-ee-as''','','one thousand ("chiliad")',':--thousand.'),
