('G5511','G','χλαμύς','chlamýs','khlam-ooce''','','a military cloak',':--robe.'),
('G5512','G','χλευάζω','chleuázō','khlyoo-ad''-zo','','to throw out the lip, i.e. jeer  at',':--mock.'),
('G5513','G','χλιαρός','chliarós','khlee-ar-os''','','tepid',':--lukewarm.'),
('G5514','G','Χλόη','Chlóē','khlo''-ay','','"green"; Chloë, a Christian  female',':--Chloe.'),
('G5515','G','χλωρός','chlōrós','khlo-ros''','','greenish, i.e. verdant, dun-colored',':--green,  pale.'),
('G5516','G','χξϛ','chx stigma','khee xee stig''-ma','','666 as a numeral',':--six hundred  threescore and six.'),
