-- Strongs Hebrew and Greek Lexicon
-- Hebrew data: OpenScriptures HebrewStrong.xml (MIT license)
-- Greek data: OpenScriptures Strongs Greek Dictionary XML 1.4 (Public Domain)

CREATE TABLE IF NOT EXISTS public.strongs_lexicon (
  id        TEXT PRIMARY KEY,   -- H7225 or G3056
  testament TEXT NOT NULL,      -- 'H' (Hebrew) or 'G' (Greek)
  script    TEXT NOT NULL DEFAULT '',  -- Hebrew/Greek script
  xlit      TEXT NOT NULL DEFAULT '',  -- Transliteration
  pron      TEXT NOT NULL DEFAULT '',  -- Pronunciation
  pos       TEXT NOT NULL DEFAULT '',  -- Part of speech (Hebrew only)
  def       TEXT NOT NULL DEFAULT '',  -- Definition / meaning
  kjv_def   TEXT NOT NULL DEFAULT ''   -- KJV gloss / usage list
);

-- No RLS needed — this is public reference data
ALTER TABLE public.strongs_lexicon ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public read strongs" ON public.strongs_lexicon
  FOR SELECT USING (true);

